import http from 'k6/http';
import { check, sleep } from 'k6';
import { Rate } from 'k6/metrics';

const errorRate = new Rate('errors');

export const options = {
  stages: [
    { duration: '2m', target: 20000 }, // Baseline
    { duration: '2m', target: 40000 }, // 2x burst
    { duration: '2m', target: 80000 }, // 4x stress test
  ],
  thresholds: {
    http_req_duration: ['p(99)<120'],
    errors: ['rate<0.005'],
  },
};

export default function () {
  const response = http.post('https://api.bidding-engine.com/bid', {
    auctionId: Math.random().toString(36),
    bidAmount: Math.floor(Math.random() * 1000),
    timestamp: Date.now(),
  });

  errorRate.add(!check(response, {
    'status is 200': (r) => r.status === 200,
    'response time < 120ms': (r) => r.timings.duration < 120,
  }));

  sleep(0.01);
}
```

