    this.targetTps = config.targetTps;
    this.peakTps = config.peakTps;
    this.throttleTo = config.throttleTo || 1800;
    this.outageRate = config.outageRate || 0.02;
    this.kafka = new Kafka({ brokers: config.brokers });
    this.producer = this.kafka.producer();
    this.metrics = [];
  }

  async initialize() {
    await this.producer.connect();
    await this.seedTestData();
  }

  async runWorkload(durationMinutes = 30) {
    const startTime = Date.now();
    let currentTps = 0;

    while (Date.now() - startTime < durationMinutes * 60000) {
      currentTps = Math.min(currentTps + 50, this.peakTps);
      const effectiveTps = Math.min(currentTps, this.throttleTo);

      await this.emitTransactions(effectiveTps);
      await this.collectMetrics();

      if (Math.random() < this.outageRate) {
        await this.simulateOutage();
      }
    }
  }

  async emitTransactions(tps) {
    const batch = [];
    for (let i = 0; i < tps; i++) {
      batch.push({
        transactionId: this.generateIdempotencyKey(),
        amount: this.sampleAmount(),
        merchantId: this.sampleMerchant(),
        timestamp: Date.now()
      });
    }

    await this.producer.send({
      topic: 'payments.authorization',
      messages: batch
    });
  }

  generateIdempotencyKey() {
    return `txn_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;
  }

  async collectMetrics() {
    const latency = await this.measureEndToEndLatency();
    this.metrics.push({
      timestamp: Date.now(),
      latency,
      tps: this.targetTps,
      errorRate: await this.measureErrorRate()
    });
  }

  generateReport() {
    const sorted = this.metrics.sort((a, b) => a.latency - b.latency);
    const p95 = sorted[Math.floor(sorted.length * 0.95)].latency;
    const p99 = sorted[Math.floor(sorted.length * 0.99)].latency;

    return { p95, p99, avgLatency: this.calculateAverage() };
  }
}

module.exports = PaymentsLoadTest;
```

## Key Takeaways

- Design tests that mirror production traffic characteristics and failure modes
- Measure tail latency (p95/p99) rather than averages to surface bottlenecks
- Validate idempotency by replaying the same idempotency keys
- Instrument comprehensively across all service boundaries for full visibility

