import http from 'k6/http';
import { check, sleep } from 'k6';
import { Rate, Trend } from 'k6/metrics';

const errorRate = new Rate('errors');
const latency = new Trend('latency');

export const options = {
  stages: [
    { duration: '2m', target: 1000 },  // Ramp-up
    { duration: '5m', target: 1000 },  // Steady state
    { duration: '2m', target: 4000 },  // Spike to 4x
    { duration: '5m', target: 4000 },  // Sustained spike
    { duration: '1m', target: 0 },    // Ramp-down
  ],
  thresholds: {
    http_req_duration: ['p(50)<200', 'p(95)<500'],
    errors: ['rate<0.01'],
  },
};

export default function () {
  const url = 'https://api.example.com/short/abc123';
  const res = http.get(url, { tags: { name: 'redirect' } });

  latency.add(res.timings.duration);
  errorRate.add(res.status !== 200 && res.status !== 302);

  check(res, {
    'status is 200 or 302': (r) => [200, 302].includes(r.status),
  });

  sleep(Math.random() * 0.5);
}
```

