function percentile(arr, p) {
  if (!Array.isArray(arr) || arr.length === 0) return 0;
  const sorted = arr.slice().sort((a,b)=>a-b);
  const idx = Math.ceil(p/100 * sorted.length) - 1;
  return sorted[Math.max(0, Math.min(idx, sorted.length-1))];
}
