import http from 'k6/http';
import { sleep } from 'k6';
import { Trend, Rate, Counter } from 'k6/metrics';

const signalingLatency = new Trend('signaling_latency');
const mediaLatency = new Trend('media_latency');
const packetLoss = new Rate('packet_loss');
const joinFailures = new Counter('join_failures');

export const options = {
  stages: [
    { duration: '5m', target: 1000 },   // Ramp
    { duration: '15m', target: 1000 },   // Soak
    { duration: '2m', target: 5000 },    // Burst spike
    { duration: '10m', target: 1000 },   // Recovery
    { duration: '5m', target: 0 }        // Cooldown
  ],
  thresholds: {
    'signaling_latency': ['p(95)<500'],
    'media_latency': ['p(95)<150'],
    'packet_loss': ['rate<0.01']
  }
};

export default function () {
  const meetingId = `meeting_${Math.floor(Math.random() * 20000)}`;

  const start = Date.now();
  const joinRes = http.post(`https://api.example.com/meetings/${meetingId}/join`);
  signalingLatency.add(Date.now() - start);

  if (joinRes.status !== 200) {
    joinFailures.add(1);
    return;
  }

  simulateMediaStream(meetingId, joinRes.json('token'));
  sleep(Math.random() * 10 + 5);

  const leaveStart = Date.now();
  http.post(`https://api.example.com/meetings/${meetingId}/leave`);
  signalingLatency.add(Date.now() - leaveStart);
}

function simulateMediaStream(meetingId, token) {
  const rtpMetrics = measureRTPMetrics(token);
  mediaLatency.add(rtpMetrics.latency);
  packetLoss.add(rtpMetrics.lostPackets / rtpMetrics.totalPackets);
}
```

This test design demonstrates understanding of realistic load patterns, comprehensive instrumentation, and proper threshold definitions for production-grade video conferencing systems.

